function FaqItem({ question, answer, theme }) {
  const [open, setOpen] = useState(false);
  return (
    <div className={`contact-faq-item ${open ? "open" : ""}`}>
      <button
        type="button"
        className="contact-faq-question"
        onClick={() => setOpen((v) => !v)}
        aria-expanded={open}
      >
        <span style={{ color: theme.text }}>{question}</span>
        <FaChevronDown className="contact-faq-chevron" aria-hidden="true" />
      </button>
      <div className="contact-faq-answer-wrap">
        <p
          className="contact-faq-answer"
          style={{ color: theme.secondaryText }}
        >
          {answer}
        </p>
      </div>
    </div>
  );
}

