import React, { useRef, useState } from "react";
import emailjs from "emailjs-com";
import toast, { Toaster } from "react-hot-toast";
import { FaPaperPlane, FaEnvelope } from "react-icons/fa";
import { socialMediaLinks } from "../../portfolio";
import "./contactform.css";

const SERVICE_ID = "service_xe6alve";
const TEMPLATE_ID = "template_k2u1z0k";
const PUBLIC_KEY = "ANZYSfODJvj2-066t";

export default function ContactForm({ theme }) {
  const formRef = useRef(null);
  const [sending, setSending] = useState(false);
  const [lastError, setLastError] = useState(null);

  const buildMailto = () => {
    const f = formRef.current;
    if (!f) return `mailto:${socialMediaLinks.gmail}`;
    const data = new FormData(f);
    const params = new URLSearchParams({
      subject: data.get("subject") || "Hello from your portfolio",
      body: `From: ${data.get("name") || ""} <${data.get("email") || ""}>\n\n${
        data.get("message") || ""
      }`,
    });
    return `mailto:${socialMediaLinks.gmail}?${params.toString()}`;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (sending) return;
    setSending(true);
    setLastError(null);

    emailjs
      .sendForm(SERVICE_ID, TEMPLATE_ID, e.target, PUBLIC_KEY)
      .then(() => {
        toast.success("Message sent — I'll get back to you soon!");
        formRef.current?.reset();
      })
      .catch((err) => {
        const detail =
          (err && (err.text || err.message)) || "Email service unavailable";
        toast.error(`Couldn't send: ${detail}`);
        setLastError(detail);
      })
      .finally(() => setSending(false));
  };

  return (
    <>
      <Toaster position="top-right" />
      <div className="contact-form-shell">
        <div className="contact-form-header">
          <h2 style={{ color: theme?.text }}>I'd love to hear from you</h2>
          <p style={{ color: theme?.secondaryText }}>
            Drop a quick message — I usually reply within 24 hours.
          </p>
        </div>

        <form
          ref={formRef}
          className="contact-form"
          onSubmit={handleSubmit}
          noValidate
        >
          <div className="contact-form-row">
            <input
              type="text"
              name="name"
              className="contact-form-text"
              placeholder="Your name"
              required
              autoComplete="name"
            />
            <input
              type="email"
              name="email"
              className="contact-form-text"
              placeholder="Your email"
              required
              autoComplete="email"
            />
          </div>

          <input
            type="text"
            name="subject"
            className="contact-form-text"
            placeholder="Subject"
            required
          />

          <textarea
            className="contact-form-text contact-form-textarea"
            name="message"
            placeholder="What would you like to discuss?"
            required
            rows={4}
          />

          {/* Honeypot for bots — hidden, real users won't touch it */}
          <input
            type="text"
            name="website"
            className="contact-form-honeypot"
            tabIndex={-1}
            autoComplete="off"
            aria-hidden="true"
          />

          <div className="contact-form-actions">
            <button
              type="submit"
              className="contact-form-btn"
              disabled={sending}
              style={{
                background: theme?.accentBright || "#2980b9",
              }}
            >
              <FaPaperPlane aria-hidden="true" />
              {sending ? "Sending…" : "Send message"}
            </button>

            {lastError && (
              <a
                className="contact-form-fallback"
                href={buildMailto()}
                rel="noopener noreferrer"
              >
                <FaEnvelope aria-hidden="true" /> Open in your email app
              </a>
            )}
          </div>

          {lastError && (
            <p className="contact-form-error" role="alert">
              The form service hit an error. You can still reach me directly at{" "}
              <a href={`mailto:${socialMediaLinks.gmail}`}>
                {socialMediaLinks.gmail}
              </a>
              .
            </p>
          )}
        </form>
      </div>
    </>
  );
}
